211	func (b DockerCloneAttemptBackend) Prepare(ctx context.Context, req AttemptBackendPrepareRequest) (*AttemptWorkspace, error) {
212		ws, err := (LocalCloneAttemptBackend{CloneMode: dockerCloneMode(b.Docker)}).Prepare(ctx, req)
213		if err != nil {
214			return nil, err
215		}
216		ws.Backend = AttemptBackendDockerClone
217		ws.KeepOnError = b.Docker != nil && b.Docker.KeepOnError
218		ws.DockerRun = executeBeadDockerRunPath(req.ProjectRoot, req.BeadID, req.AttemptID)
219		ws.DockerHome = filepath.Join(ws.DockerRun, "home")
220		if err := prepareDockerAttemptRuntime(ws.DockerRun); err != nil {
221			_ = os.RemoveAll(ws.WorkDir)
222			return nil, err
223		}
224		if err := prepareDockerAttemptHome(ws.DockerHome); err != nil {
225			_ = os.RemoveAll(ws.WorkDir)
226			_ = os.RemoveAll(ws.DockerRun)
227			return nil, err
228		}
229		if !dockerSharedGoCacheDisabled(b.Docker) {
230			shared := dockerSharedGoCachePath(req.ProjectRoot)
231			if err := os.MkdirAll(shared, 0o700); err == nil {
232				ws.DockerSharedGoCache = shared
233			}
234		}
235		return ws, nil
236	}
