325	func (DockerCloneAttemptBackend) Cleanup(ctx context.Context, ws *AttemptWorkspace) error {
326		if ws != nil {
327			_ = dockerRemoveContainer(context.Background(), dockerContainerName(ws))
328			if ws.DockerHome != "" {
329				_ = os.RemoveAll(ws.DockerHome)
330			}
331			if ws.DockerRun != "" {
