431	func acquireExclusiveLock(lockFile *os.File) error {
432		if lockFile == nil {
433			return fmt.Errorf("lock file is nil")
434		}
435		return inTreeLockAcquire(lockFile)
436	}
437	
438	func releaseExclusiveLock(lockFile *os.File) error {
439		if lockFile == nil {
440			return nil
441		}
442		return inTreeLockRelease(lockFile)
443	}
