457	// dockerSharedCacheRoot is a per-project directory used to persist caches
458	// (notably Go's build cache) across attempts. Living outside the per-attempt
459	// runtime dir means it survives Cleanup() and is reused on the next attempt,
460	// turning cold Go builds into warm ones.
461	func dockerSharedCacheRoot(projectRoot string) string {
462		return filepath.Join(config.ExecutionTempRoot(projectRoot), ".ddx-shared-cache-"+shortPathHash(projectRoot))
463	}
464	
465	func dockerSharedGoCachePath(projectRoot string) string {
466		return filepath.Join(dockerSharedCacheRoot(projectRoot), "gocache")
467	}
