469	func localCloneArgs(mode, projectRoot, clonePath string) []string {
470		cloneArgs := []string{"clone", "--no-checkout"}
471		switch strings.ToLower(strings.TrimSpace(mode)) {
472		case "copy", "no-hardlinks", "no-hardlink":
473			cloneArgs = append(cloneArgs, "--no-hardlinks")
474		default:
475			cloneArgs = append(cloneArgs, "--local")
476		}
477		return append(cloneArgs, projectRoot, clonePath)
478	}
479	
480	func shouldRetryCloneWithoutHardlinks(mode string, out []byte) bool {
481		switch strings.ToLower(strings.TrimSpace(mode)) {
482		case "copy", "no-hardlinks", "no-hardlink":
483			return false
484		}
485		msg := strings.ToLower(string(out))
486		return strings.Contains(msg, "invalid cross-device link") ||
487			strings.Contains(msg, "operation not permitted")
488	}
