494	func seedAttemptCloneUserConfig(ctx context.Context, projectRoot, clonePath string) {
495		userName := strings.TrimSpace(gitConfigValue(ctx, projectRoot, "user.name"))
496		userEmail := strings.TrimSpace(gitConfigValue(ctx, projectRoot, "user.email"))
497		if userName == "" {
498			userName = "ddx"
499		}
500		if userEmail == "" {
501			userEmail = "ddx@local"
502		}
503		_ = internalgit.Command(ctx, clonePath, "config", "user.name", userName).Run()
504		_ = internalgit.Command(ctx, clonePath, "config", "user.email", userEmail).Run()
505	}
