549	func gitConfigValue(ctx context.Context, dir, key string) string {
550		out, err := internalgit.Command(ctx, dir, "config", "--get", key).Output()
551		if err != nil {
552			return ""
553		}
554		return strings.TrimSpace(string(out))
555	}
