588	func resolveDockerAttemptImage(ctx context.Context, cfg *config.ExecutionsDockerConfig, projectRoot, baseImage string) (string, error) {
589		if cfg != nil && strings.TrimSpace(cfg.ProjectImage) != "" {
590			return strings.TrimSpace(cfg.ProjectImage), nil
591		}
