593		if err != nil || !ok {
594			return baseImage, err
595		}
596		contextDir, err := dockerProjectContext(projectRoot, cfg)
597		if err != nil {
598			return "", err
599		}
600		tag := "ddx-project-attempt-" + shortPathHash(projectRoot) + ":latest"
601		if skipRebuildIfImagePresent(cfg) && dockerImageExists(ctx, tag) {
602			return tag, nil
603		}
604		args := []string{
605			"build", "-q",
606			"--build-arg", "DDX_BASE_IMAGE=" + baseImage,
607			"-f", dockerfile,
608			"-t", tag,
609			contextDir,
610		}
611		if out, err := exec.CommandContext(ctx, "docker", args...).CombinedOutput(); err != nil {
612			return "", fmt.Errorf("building docker project attempt image: %s: %w", strings.TrimSpace(string(out)), err)
613		}
614		return tag, nil
615	}
