894	func copyDockerAuthFileIfExists(src, dst string) error {
895		info, err := os.Stat(src)
896		if err != nil {
897			if os.IsNotExist(err) {
898				return nil
899			}
900			return fmt.Errorf("stat docker auth file %s: %w", src, err)
901		}
902		if info.IsDir() {
903			return nil
904		}
905		raw, err := os.ReadFile(src)
906		if err != nil {
907			return fmt.Errorf("read docker auth file %s: %w", src, err)
908		}
909		if err := os.MkdirAll(filepath.Dir(dst), 0o700); err != nil {
910			return fmt.Errorf("create docker auth dir %s: %w", filepath.Dir(dst), err)
911		}
912		if err := os.WriteFile(dst, raw, 0o600); err != nil {
913			return fmt.Errorf("write docker auth file %s: %w", dst, err)
914		}
915		return nil
916	}
