// dockerAttemptCommand creates an exec.Cmd for a docker invocation with process-group cleanup.
// The command is configured with:
// - cmdSetProcessGroup: Sets Setpgid=true and Pdeathsig=SIGKILL (on Unix) to ensure that
//   all child processes and the docker command itself are killed if the parent thread dies abnormally.
// - exec.CommandContext: Uses context cancellation to gracefully shut down the command on worker exit.
// - --rm flag: Added by dockerRunArgs to ensure the docker container is removed automatically on exit.
// - --init flag: Added by dockerRunArgs to ensure proper signal handling inside the container.
// Together, these guarantee that nested harness processes inside the docker container are cleaned up
// when the worker exits, either gracefully (via context cancellation) or abnormally (via Pdeathsig).
func dockerAttemptCommand(ctx context.Context, args ...string) *exec.Cmd {
	cmd := exec.CommandContext(ctx, "docker", args...)
	cmdSetProcessGroup(cmd)
	return cmd
}
